package embedder

import (
	"bytes"
	"context"
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"time"

	"github.com/a<HOME>/agentic-rag-mcp/internal/config"
)

// OllamaBackend implements Embedder via HTTP calls to a running Ollama instance.
type OllamaBackend struct {
	host       string
	model      string
	dimensions int
	maxTokens  int
	client     *http.Client
}

type ollamaEmbedRequest struct {
	Model string   `json:"model"`
	Input []string `json:"input"`
}

type ollamaEmbedResponse struct {
	Embeddings [][]float64 `json:"embeddings"`
}

// NewOllamaBackend constructs an Ollama embedding backend.
// It performs a health check at construction time and fails fast if Ollama is unreachable.
func NewOllamaBackend(cfg config.EmbedderConfig) (*OllamaBackend, error) {
	host := cfg.Ollama.Host
	if host == "" {
		host = "http://localhost:11434"
	}

	client := &http.Client{Timeout: 30 * time.Second}

	ob := &OllamaBackend{
		host:       host,
		model:      cfg.Model,
		dimensions: cfg.Dimensions,
		maxTokens:  cfg.MaxTokens,
		client:     client,
	}

	// Health check: verify Ollama is reachable
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	_, err := ob.Embed(ctx, "health check", PurposeQuery)
	if err != nil {
		return nil, fmt.Errorf("ollama not reachable at %s: %w", host, err)
	}

	return ob, nil
}

// NewOllamaBackendNoHealthCheck constructs an Ollama backend without the startup health check.
// Useful for testing.
func NewOllamaBackendNoHealthCheck(cfg config.EmbedderConfig) *OllamaBackend {
	host := cfg.Ollama.Host
	if host == "" {
		host = "http://localhost:11434"
	}
	return &OllamaBackend{
		host:       host,
		model:      cfg.Model,
		dimensions: cfg.Dimensions,
		maxTokens:  cfg.MaxTokens,
		client:     &http.Client{Timeout: 30 * time.Second},
	}
}

func (o *OllamaBackend) Embed(ctx context.Context, text string, purpose Purpose) ([]float32, error) {
	vecs, err := o.embedRaw(ctx, []string{o.prefixed(text, purpose)})
	if err != nil {
		return nil, err
	}
	if len(vecs) == 0 {
		return nil, fmt.Errorf("ollama returned no embeddings")
	}
	return vecs[0], nil
}

func (o *OllamaBackend) EmbedBatch(ctx context.Context, texts []string, purpose Purpose) ([][]float32, error) {
	prefixed := make([]string, len(texts))
	for i, t := range texts {
		prefixed[i] = o.prefixed(t, purpose)
	}
	return o.embedRaw(ctx, prefixed)
}

func (o *OllamaBackend) Dimensions() int { return o.dimensions }
func (o *OllamaBackend) MaxTokens() int  { return o.maxTokens }
func (o *OllamaBackend) Close() error    { return nil }

// prefixed prepends the task prefix based on purpose.
func (o *OllamaBackend) prefixed(text string, purpose Purpose) string {
	switch purpose {
	case PurposeIndex:
		return "search_document: " + text
	case PurposeQuery:
		return "search_query: " + text
	default:
		return text
	}
}

// embedRaw sends the embed request to Ollama and returns float32 vectors.
func (o *OllamaBackend) embedRaw(ctx context.Context, inputs []string) ([][]float32, error) {
	reqBody := ollamaEmbedRequest{
		Model: o.model,
		Input: inputs,
	}

	body, err := json.Marshal(reqBody)
	if err != nil {
		return nil, fmt.Errorf("marshalling embed request: %w", err)
	}

	url := o.host + "/api/embed"
	req, err := http.NewRequestWithContext(ctx, http.MethodPost, url, bytes.NewReader(body))
	if err != nil {
		return nil, fmt.Errorf("creating request: %w", err)
	}
	req.Header.Set("Content-Type", "application/json")

	resp, err := o.client.Do(req)
	if err != nil {
		return nil, fmt.Errorf("calling ollama: %w", err)
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		respBody, _ := io.ReadAll(resp.Body)
		return nil, fmt.Errorf("ollama returned status %d: %s", resp.StatusCode, string(respBody))
	}

	var ollamaResp ollamaEmbedResponse
	if err := json.NewDecoder(resp.Body).Decode(&ollamaResp); err != nil {
		return nil, fmt.Errorf("decoding ollama response: %w", err)
	}

	// Convert float64 -> float32 and validate dimensions
	result := make([][]float32, len(ollamaResp.Embeddings))
	for i, emb := range ollamaResp.Embeddings {
		if o.dimensions > 0 && len(emb) != o.dimensions {
			return nil, fmt.Errorf("dimension mismatch: expected %d, got %d", o.dimensions, len(emb))
		}
		vec := make([]float32, len(emb))
		for j, v := range emb {
			vec[j] = float32(v)
		}
		result[i] = vec
	}

	return result, nil
}
